import React from 'react';
import { motion } from 'framer-motion';
import './Experience.css';

const Experience = () => {
  const experiences = [
    {
      title: "DB  Engineer",
      company: "Allied Bank HeadOffice Lahore",
      period: "Nov 2025 - Present",
      description: "W",
      achievements: [
        "Reduced infrastructure costs by 40% through optimization",
        "Implemented CI/CD pipelines for 15+ applications",
        "Managed multi-region AWS deployments"
      ]
    },
    {
      title: "Data Engineer Trainee",
      company: "Systems Limited Lahore",
      period: "Sep 2025 - Nov 2025",
      description: "Worked on data pipelines using Azure Data Factory and SSIS, with analytics on Snowflake SQL and advanced BI reporting in Tableau.",
      achievements: [
        "Built and optimized end-to-end ETL pipelines using Azure Data Factory and SSIS",
        "Designed advanced Tableau dashboards for business and executive reporting",
        "Improved data reliability and performance through Snowflake SQL optimization",
        "Delivered actionable insights by transforming raw data into BI-ready datasets"
      ]

    }

  ];

  return (
    <section id="experience" className="experience-section">
      <div className="container">
        <motion.h2 
          className="section-title"
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          Professional Experience
        </motion.h2>
        <div className="experience-timeline">
          {experiences.map((exp, index) => (
            <motion.div 
              key={index}
              className="experience-item"
              initial={{ opacity: 0, x: index % 2 === 0 ? -50 : 50 }}
              whileInView={{ opacity: 1, x: 0 }}
              transition={{ delay: index * 0.2, duration: 0.6 }}
              viewport={{ once: true }}
            >
              <div className="experience-content">
                <div className="experience-header">
                  <h3>{exp.title}</h3>
                  <span className="company">{exp.company}</span>
                  <span className="period">{exp.period}</span>
                </div>
                <p className="description">{exp.description}</p>
                <ul className="achievements">
                  {exp.achievements.map((achievement, i) => (
                    <li key={i}>{achievement}</li>
                  ))}
                </ul>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
